css:
@import url('https://fonts.googleapis.com/css2?family=Cairo:wght@400;500;600&display=swap');

* {
    font-family: 'Cairo', sans-serif;
}

body {
    font-weight: 500;
    color: #2f3b52;
}

p {
    font-weight: 500;
    color: #3a3a3a;
}

div {
    font-weight: 500;
    color: #2f3b52;
}

td {
    font-weight: 500;
    color: #2f3b52;
}

li {
    font-weight: 500;
    color: #3a3a3a;
}

.rtl {
    direction: rtl;
    text-align: right;
}

.ltr {
    direction: ltr;
    text-align: left;
}

h1 {
    font-weight: 600;
    color: #1f2d3d;
}

h2 {
    font-weight: 600;
    color: #ff4d4d;
}

h3 {
    font-weight: 600;
    color: #0000ff;
}

h4 {
    font-weight: 600;
    color: #3d6cff;
}

h5 {
    font-weight: 600;
    color: #666;
}

h6 {
    font-weight: 600;
    color: #777;
}

label {
    font-weight: 600;
    color: #2f3b52;
    background-color: #e8eef5;
    padding: 3px 8px;
    border-radius: 4px;
    display: inline-block;
    border: 1px solid #d6dee8;
}
